//        ->where('c.cpf', '=', $d['cpf'])
//        ->update(['a.numero_cracha' => $d['numero_cracha']]);

        $adms = DB::table('admissoes as a')
            ->select(['a.feedback_id', 'a.id'])
            ->join('feedback_curriculos as fc', 'a.feedback_id', '=', 'fc.id')
            ->join('curriculos as c', 'fc.curriculo_id', '=', 'c.id')
            ->where('fc.empresa_id', '=', $empresa_id)
            ->where('c.cpf', '=', $d['cpf']);


        foreach ($adms->get() as $adm) {

            $demissao = [
                'feedback_id' => $adm->feedback_id,
                'data_desmobilizacao' => (new \MasterTag\DataHora($d['data_desmobilizacao']))->dataInsert(),
                'motivo_rescisao_id' => $d['motivo_rescisao_id'],
                'tipo_aviso_id' => $d['tipo_aviso_id'],
                'comentario' => $d['comentario'],
                'cipa' => 1,
                'solicitado_por' => 'importacao',
                'user_id' => $empresa_id
            ];

            $dm = \App\Models\Demissao::where('feedback_id', '=', $demissao['feedback_id'])->first();
            if (!$dm) {
                $create = \App\Models\Demissao::create($demissao);
            }

            \App\Models\Admissao::where('id', '=', $adm->id)
                ->update([
                    'matricula' => $d['matricula'],
                    'status' => 'DEMITIDO'
                ]);

            $msg = "COLABORADOR CPF ENCONTRADO NA PLANILHA PARA DEMITIR: " . $d['cpf'] . PHP_EOL;
            fwrite($outputHandle, $msg);
        }
        DB::commit();

    }
    fclose($outputHandle);
} catch (\Exception $e) {
    DB::rollBack();
    dd($e);
